import React, { useState } from 'react';

const AisleFinder = () => {
  const [file, setFile] = useState(null);
  const [textInput, setTextInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [groceryList, setGroceryList] = useState('');
  const [error, setError] = useState('');

  const handleFileUpload = (event) => {
    const selectedFile = event.target.files[0];
    if (selectedFile && selectedFile.type === 'text/plain') {
      setFile(selectedFile);
      setError('');
    } else {
      setError('Please select a valid text file');
      setFile(null);
    }
  };

  const processGroceryList = async () => {
    if (!file && !textInput.trim()) {
      setError('Please select a file or enter grocery items');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const formData = new FormData();

      if (file) {
        formData.append('file', file);
      } else {
        // Create a blob from text input
        const blob = new Blob([textInput], { type: 'text/plain' });
        formData.append('file', blob, 'grocery-list.txt');
      }

      formData.append('output_format', 'aisle');
      formData.append('store', '4500S Smiths');

      const response = await fetch('http://localhost:5001/api/process-grocery-list', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Failed to process grocery list');
      }

      const result = await response.text();
      setGroceryList(result);
    } catch (err) {
      setError('Error processing grocery list: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(groceryList);
      alert('Grocery list copied to clipboard!');
    } catch (err) {
      setError('Failed to copy to clipboard');
    }
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h1 style={{ textAlign: 'center', color: '#2c3e50', marginBottom: '30px' }}>
        Aisle Finder
      </h1>

      <div style={{ display: 'flex', gap: '20px', marginBottom: '20px' }}>
        {/* Text Input Section */}
        <div style={{ flex: '1' }}>
          <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>
            Type or Paste Grocery List:
          </label>
          <textarea
            value={textInput}
            onChange={(e) => setTextInput(e.target.value)}
            placeholder="Enter grocery items, one per line:&#10;milk&#10;bread&#10;eggs&#10;apples"
            style={{
              width: '100%',
              height: '200px',
              padding: '10px',
              border: '1px solid #ddd',
              borderRadius: '4px',
              fontSize: '14px',
              fontFamily: 'Arial, sans-serif',
              resize: 'vertical',
              overflowY: 'auto'
            }}
          />
        </div>

        {/* File Upload Section */}
        <div style={{ flex: '1' }}>
          <div style={{ marginBottom: '10px' }}>
            <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>
              Or Upload Text File:
            </label>
            <input
              type="file"
              accept=".txt"
              onChange={handleFileUpload}
              style={{
                padding: '8px',
                border: '1px solid #ddd',
                borderRadius: '4px',
                width: '100%'
              }}
            />
          </div>

          {file && (
            <p style={{ color: '#27ae60', fontSize: '14px' }}>
              Selected: {file.name}
            </p>
          )}

          <div style={{ marginTop: '20px', padding: '10px', backgroundColor: '#f8f9fa', borderRadius: '4px', border: '1px solid #e9ecef' }}>
            <p style={{ margin: '0', fontSize: '12px', color: '#6c757d' }}>
              <strong>How it works:</strong><br/>
              Enter items in the text box or upload a file. Each line should contain one grocery item. 
              The system will organize items by store aisle for efficient shopping.
            </p>
          </div>
        </div>
      </div>

      <button
        onClick={processGroceryList}
        disabled={(!file && !textInput.trim()) || loading}
        style={{
          backgroundColor: (!file && !textInput.trim()) || loading ? '#95a5a6' : '#3498db',
          color: 'white',
          padding: '12px 24px',
          border: 'none',
          borderRadius: '4px',
          cursor: (!file && !textInput.trim()) || loading ? 'not-allowed' : 'pointer',
          fontSize: '16px',
          marginBottom: '20px'
        }}
      >
        {loading ? 'Processing...' : 'Process Grocery List'}
      </button>

      {error && (
        <div style={{
          backgroundColor: '#e74c3c',
          color: 'white',
          padding: '10px',
          borderRadius: '4px',
          marginBottom: '20px'
        }}>
          {error}
        </div>
      )}

      {groceryList && (
        <div style={{ marginTop: '20px' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
            <h3 style={{ margin: '0', color: '#2c3e50' }}>Organized Grocery List:</h3>
            <button
              onClick={copyToClipboard}
              style={{
                backgroundColor: '#27ae60',
                color: 'white',
                padding: '8px 16px',
                border: 'none',
                borderRadius: '4px',
                cursor: 'pointer',
                fontSize: '14px'
              }}
            >
              Copy to Clipboard
            </button>
          </div>

          <pre style={{
            backgroundColor: '#f8f9fa',
            padding: '15px',
            borderRadius: '4px',
            border: '1px solid #e9ecef',
            whiteSpace: 'pre-wrap',
            fontFamily: 'monospace',
            maxHeight: '400px',
            overflowY: 'auto'
          }}>
            {groceryList}
          </pre>
        </div>
      )}
    </div>
  );
};

export default AisleFinder;
